const raw = $input.first().json;
const payload = raw.body || raw;
const headers = raw.headers || {};

const authHeader = headers.authorization || headers.Authorization || '';
if (authHeader !== 'Bearer ' + $env.DASHBOARD_API_TOKEN) {
  return [{ json: { success: false, http_status: 401, error: 'Unauthorized' } }];
}

const topic_id = payload.topic_id;
const production_register = payload.production_register;
const compat_status = payload.compat_status || null;
const VALID = ['REGISTER_01_ECONOMIST','REGISTER_02_PREMIUM','REGISTER_03_NOIR','REGISTER_04_SIGNAL','REGISTER_05_ARCHIVE'];

if (!topic_id) return [{ json: { success: false, http_status: 400, error: 'topic_id required' } }];
if (!VALID.includes(production_register)) {
  return [{ json: { success: false, http_status: 400, error: 'Invalid production_register. Must be one of ' + VALID.join(', ') } }];
}

const SB = $env.SUPABASE_URL;
const SRK = $env.SUPABASE_SERVICE_ROLE_KEY;
const sbHeaders = { 'apikey': SRK, 'Authorization': `Bearer ${SRK}`, 'Content-Type': 'application/json' };

// 1. Read topic to ensure we have video_ratio + scene_count for scene-classify call
const topicRes = await fetch(`${SB}/rest/v1/topics?id=eq.${topic_id}&select=id,video_ratio,production_mode,scene_count,pipeline_stage`, { headers: sbHeaders });
const topicArr = await topicRes.json();
const topic = topicArr[0];
if (!topic) return [{ json: { success: false, http_status: 404, error: 'Topic not found' } }];

// 2. PATCH topic with register selection
//    Topic-stage (Gate 1): scene_count === 0 → only record register, do NOT set pipeline_stage
//    Script-stage (ProductionMonitor): scene_count > 0 → advance pipeline_stage to 'classifying'
const now = new Date().toISOString();
const isTopicStage = (topic.scene_count || 0) === 0;
const patchPayload = isTopicStage
  ? { production_register, register_selected_at: now, updated_at: now }
  : { production_register, register_selected_at: now, pipeline_stage: 'classifying', updated_at: now };
const patchRes = await fetch(`${SB}/rest/v1/topics?id=eq.${topic_id}`, {
  method: 'PATCH',
  headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
  body: JSON.stringify(patchPayload)
});
if (!patchRes.ok) {
  const err = await patchRes.text();
  return [{ json: { success: false, http_status: patchRes.status, error: 'PATCH failed: ' + err.slice(0, 400) } }];
}

// 3. Log
await fetch(`${SB}/rest/v1/production_logs`, {
  method: 'POST',
  headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
  body: JSON.stringify({
    topic_id,
    stage: 'register_approve',
    action: 'completed',
    status: 'success',
    metadata: { production_register, production_mode: topic.production_mode, compat_status }
  })
}).catch(e => console.warn('Log failed: ' + e.message));

// 4. Fire scene-classify (downstream pipeline continuation) — ONLY at script-stage
let classifyTriggered = false;
let classifyError = null;
if (isTopicStage) {
  classifyError = 'skipped_topic_stage';
} else try {
  const base = $env.N8N_WEBHOOK_BASE;
  const token = $env.DASHBOARD_API_TOKEN;
  const cRes = await fetch(`${base}/scene-classify`, {
    method: 'POST',
    headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      topic_id,
      video_ratio: topic.video_ratio || '100_0',
      scene_count: topic.scene_count || 0,
      production_register
    })
  });
  classifyTriggered = cRes.ok;
  if (!cRes.ok) {
    const err = await cRes.text();
    classifyError = `HTTP ${cRes.status}: ${err.slice(0, 200)}`;
  }
} catch (e) {
  classifyError = e.message;
}

return [{ json: { success: true, http_status: 200, topic_id, production_register, stage: isTopicStage ? 'topic' : 'script', classify_triggered: classifyTriggered, classify_error: classifyError } }];
